def range_summary(nums):
    if not nums:
        return ''

    result, start, count = [], nums[0], 1

    for num in nums[1:]:
        if num == start + 1:
            count += 1
        elif num == start:
            result.append(f'{start}-{start}' if count == 1 else f'{start}-{start+count-1}')
            start = num
            count = 1

    # handle the last range and any remaining single number
    if count > 1:
        result.append(f'{start}-{start+count-1}')
    elif start != nums[-1]:
        result.append(str(start))

    return ', '.join(result)
